module asyn_fifo (
    input wclk, 
    input rclk, 
    input wrstn, 
    input rrstn, 
    input winc, 
    input rinc, 
    input [7:0] wdata, 
    output wfull, 
    output rempty, 
    output [7:0] rdata
);
    parameter WIDTH = 8;
    parameter DEPTH = 16;

    wire [WIDTH-1:0] ram_data;
    wire [WIDTH-1:0] ram_addr_w;
    wire [WIDTH-1:0] ram_addr_r;
    wire ram_we;
    wire ram_re;
    wire [WIDTH-1:0] ram_din;
    wire [WIDTH-1:0] ram_dout;
    dual_port_RAM #(.DEPTH(DEPTH), .WIDTH(WIDTH)) ram_inst (
        .wclk(wclk),
        .wenc(ram_we),
        .waddr(ram_addr_w),
        .wdata(ram_din),
        .rclk(rclk),
        .renc(ram_re),
        .raddr(ram_addr_r),
        .rdata(ram_dout)
    );

    reg [3:0] waddr_buff;
    reg [3:0] wptr;
    reg [3:0] wptr_buff;
    always @(posedge wclk or negedge wrstn) begin
        if (!wrstn)
            waddr_buff <= 0;
            waddr_buff <= waddr_buff + winc;
    end

    always @(posedge wclk or negedge wrstn) begin
        if (!wrstn)
            wptr <= 0;
            wptr <= {waddr_buff[3], waddr_buff[2], waddr_buff[1], waddr_buff[0]} ^ {waddr_buff[3], waddr_buff[2], waddr_buff[1], waddr_buff[0] >> 1};
    end

    always @(posedge wclk or negedge wrstn) begin
        if (!wrstn)
            wptr_buff <= 0;
            wptr_buff <= wptr;
    end

    reg [3:0] raddr_buff;
    reg [3:0] rptr;
    reg [3:0] rptr_buff;
    always @(posedge rclk or negedge rrstn) begin
        if (!rrstn)
            raddr_buff <= 0;
            raddr_buff <= raddr_buff + rinc;
    end

    always @(posedge rclk or negedge rrstn) begin
        if (!rrstn)
            rptr <= 0;
            rptr <= {raddr_buff[3], raddr_buff[2], raddr_buff[1], raddr_buff[0]} ^ {raddr_buff[3], raddr_buff[2], raddr_buff[1], raddr_buff[0] >> 1};
    end

    always @(posedge rclk or negedge rrstn) begin
        if (!rrstn)
            rptr_buff <= 0;
            rptr_buff <= rptr;
    end

    assign wfull = (wptr == ~rptr_buff[3:0]);
    assign rempty = (rptr == wptr_buff);

    assign ram_we = winc && !wfull;
    assign ram_re = rinc && !rempty;
    assign ram_addr_w = waddr_buff;
    assign ram_addr_r = raddr_buff;
    assign ram_din = wdata;
    assign rdata = ram_dout;
endmodule
